sql:
SELECT location, COUNT(sensor_id) AS number_of_sensors
FROM sensors
GROUP BY location;

SELECT AVG(battery_level) AS average_battery_level
FROM sensors
WHERE location = 'Living Room' AND firmware_version > '1.0.0';

SELECT sensor_id, sensor_name, battery_level
FROM sensors
ORDER BY battery_level DESC;

SELECT s.sensor_id, sh.status, sh.health_score
FROM sensors s
INNER JOIN sensor_health sh ON s.sensor_id = sh.sensor_id;

external_knowledge:
- 'gadgets' refers to sensors;
- 'cooking area' refers to the Kitchen location;
- 'recently inspected within the past year' means the last_checked timestamp is within the last year.

sql:
SELECT AVG(battery_level) AS average_battery_level
FROM sensors
WHERE firmware_version > '1.0.0' AND location IN ('Living Room', 'Bedroom');

external_knowledge:
- 'shining like beacons of reliability' is a metaphor indicating the top three in terms of health score and operational status; 
- 'not been troubled by any issues' refers to sensors with no reported issues; 
- 'air conditioners' refers to sensors of type 'Air Conditioner'.

- 'Best-performing sensors' refers to sensors with the top three health scores in each location;
- 'Most and least significant data points' corresponds to the maximum and minimum data values in JSON format;
- 'Average quality of their data' is the mean data quality score for the sensors in question.

sql:
SELECT AVG(data_quality_score) AS average_data_quality
FROM sensor_data
WHERE timestamp BETWEEN '2023-04-01 00:00:00' AND '2023-04-30 23:59:59';

SELECT AVG(battery_level) AS average_battery_level
FROM sensors
WHERE location = 'Living Room' AND battery_level > 50;
